@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings

<nav class="settings-sidebar" role="tablist" aria-label="Settings navigation">
    <h3 class="sidebar-title">Settings</h3>
    <ul class="sidebar-nav">
        @foreach (var section in _sections)
        {
            var isActive = ActiveSection == section.Name;
            <li class="sidebar-item @(isActive ? "active" : "")"
                role="tab"
                aria-selected="@isActive"
                @onclick="() => OnSectionChanged.InvokeAsync(section.Name)">
                <span class="sidebar-icon" aria-hidden="true">@section.Icon</span>
                <span>@section.Name</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly SectionInfo[] _sections =
    [
        new("Profile", "👤"),
        new("Notifications", "🔔"),
        new("Security", "🔒"),
        new("Appearance", "🎨"),
    ];

    private readonly record struct SectionInfo(string Name, string Icon);
}

.settings-sidebar {
    width: 240px;
    background: var(--sidebar-bg, #f8f9fa);
    border-right: 1px solid var(--border-color, #dee2e6);
    padding: 1.5rem 0;
    flex-shrink: 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--text-primary, #212529);
}

.sidebar-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    color: var(--text-secondary, #495057);
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
    font-size: 0.95rem;
}

.sidebar-item:hover {
    background: var(--sidebar-hover, #e9ecef);
    color: var(--text-primary, #212529);
}

.sidebar-item.active {
    background: var(--sidebar-active-bg, #e7f1ff);
    color: var(--accent-color, #0d6efd);
    border-left-color: var(--accent-color, #0d6efd);
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.15rem;
    width: 1.5rem;
    text-align: center;
}

@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings

<div class="change-password-panel">
    <button class="panel-toggle" @onclick="ToggleExpanded">
        <span class="toggle-icon">@(_expanded ? "▼" : "▶")</span>
        Change Password
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" @bind="_currentPassword" />
            </div>

            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" @bind="_newPassword" />
            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" />
            </div>

            @if (_errorMessage is not null)
            {
                <div class="message error">@_errorMessage</div>
            }
            @if (_successMessage is not null)
            {
                <div class="message success">@_successMessage</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _errorMessage;
    private string? _successMessage;
    private bool _saving;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _errorMessage = null;
        _successMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _errorMessage = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _errorMessage = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "Passwords do not match.";
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _successMessage = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

.change-password-panel {
    border: 1px solid var(--border-color, #dee2e6);
    border-radius: 8px;
    overflow: hidden;
}

.panel-toggle {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.875rem 1rem;
    background: var(--card-bg, #fff);
    border: none;
    cursor: pointer;
    font-size: 0.95rem;
    font-weight: 500;
    color: var(--text-primary, #212529);
    text-align: left;
}

.panel-toggle:hover {
    background: var(--sidebar-hover, #f8f9fa);
}

.toggle-icon {
    font-size: 0.7rem;
    width: 1rem;
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid var(--border-color, #dee2e6);
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings
@using sv_5abde9ea4cc94681bbd40a33fead36ea.Services

<div class="active-sessions">
    <h4>Active Sessions</h4>
    <table class="sessions-table">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-danger-sm" @onclick="() => PromptRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="current-badge">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (_sessionToRevoke is not null)
    {
        <div class="dialog-backdrop" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation>
                <h4>Revoke Session</h4>
                <p>
                    Are you sure you want to revoke the session on
                    <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?
                </p>
                <div class="dialog-actions">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var elapsed = DateTime.UtcNow - lastActive;
        return elapsed.TotalMinutes < 1 ? "Just now"
            : elapsed.TotalMinutes < 60 ? $"{(int)elapsed.TotalMinutes}m ago"
            : elapsed.TotalHours < 24 ? $"{(int)elapsed.TotalHours}h ago"
            : $"{(int)elapsed.TotalDays}d ago";
    }
}

.active-sessions h4 {
    margin: 0 0 0.75rem;
    font-size: 1rem;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.625rem 0.75rem;
    text-align: left;
    border-bottom: 1px solid var(--border-color, #dee2e6);
}

.sessions-table th {
    font-weight: 600;
    color: var(--text-secondary, #495057);
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.current-badge {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    background: var(--accent-bg, #e7f1ff);
    color: var(--accent-color, #0d6efd);
    border-radius: 4px;
    font-weight: 500;
}

.btn-danger-sm {
    padding: 0.25rem 0.625rem;
    font-size: 0.8rem;
    background: #dc3545;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.btn-danger-sm:hover {
    background: #bb2d3b;
}

/* Confirmation dialog */
.dialog-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.confirm-dialog {
    background: var(--card-bg, #fff);
    border-radius: 10px;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.15);
}

.confirm-dialog h4 {
    margin: 0 0 0.5rem;
}

.confirm-dialog p {
    margin: 0 0 1.25rem;
    color: var(--text-secondary, #495057);
}

.dialog-actions {
    display: flex;
    gap: 0.5rem;
    justify-content: flex-end;
}

