@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings

<div class="change-password-panel">
    <button class="panel-toggle" @onclick="ToggleExpanded">
        <span class="toggle-icon">@(_expanded ? "▼" : "▶")</span>
        Change Password
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" @bind="_currentPassword" />
            </div>

            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" @bind="_newPassword" />
            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" />
            </div>

            @if (_errorMessage is not null)
            {
                <div class="message error">@_errorMessage</div>
            }
            @if (_successMessage is not null)
            {
                <div class="message success">@_successMessage</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _errorMessage;
    private string? _successMessage;
    private bool _saving;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _errorMessage = null;
        _successMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _errorMessage = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _errorMessage = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "Passwords do not match.";
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _successMessage = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

