@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings
@using sv_5abde9ea4cc94681bbd40a33fead36ea.Services

<div class="active-sessions">
    <h4>Active Sessions</h4>
    <table class="sessions-table">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-danger-sm" @onclick="() => PromptRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="current-badge">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (_sessionToRevoke is not null)
    {
        <div class="dialog-backdrop" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation>
                <h4>Revoke Session</h4>
                <p>
                    Are you sure you want to revoke the session on
                    <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?
                </p>
                <div class="dialog-actions">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var elapsed = DateTime.UtcNow - lastActive;
        return elapsed.TotalMinutes < 1 ? "Just now"
            : elapsed.TotalMinutes < 60 ? $"{(int)elapsed.TotalMinutes}m ago"
            : elapsed.TotalHours < 24 ? $"{(int)elapsed.TotalHours}h ago"
            : $"{(int)elapsed.TotalDays}d ago";
    }
}

.active-sessions h4 {
    margin: 0 0 0.75rem;
    font-size: 1rem;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.625rem 0.75rem;
    text-align: left;
    border-bottom: 1px solid var(--border-color, #dee2e6);
}

.sessions-table th {
    font-weight: 600;
    color: var(--text-secondary, #495057);
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.current-badge {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    background: var(--accent-bg, #e7f1ff);
    color: var(--accent-color, #0d6efd);
    border-radius: 4px;
    font-weight: 500;
}

.btn-danger-sm {
    padding: 0.25rem 0.625rem;
    font-size: 0.8rem;
    background: #dc3545;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.btn-danger-sm:hover {
    background: #bb2d3b;
}

/* Confirmation dialog */
.dialog-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.confirm-dialog {
    background: var(--card-bg, #fff);
    border-radius: 10px;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.15);
}

.confirm-dialog h4 {
    margin: 0 0 0.5rem;
}

.confirm-dialog p {
    margin: 0 0 1.25rem;
    color: var(--text-secondary, #495057);
}

.dialog-actions {
    display: flex;
    gap: 0.5rem;
    justify-content: flex-end;
}

