@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings
@using sv_5abde9ea4cc94681bbd40a33fead36ea.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Appearance</h2>

    @if (_loading)
    {
        <p class="loading-text">Loading appearance settings…</p>
    }
    else
    {
        <div class="appearance-form">
            <fieldset class="option-group">
                <legend>Theme</legend>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-option">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </fieldset>

            <fieldset class="option-group">
                <legend>Font Size</legend>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-option">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </fieldset>

            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <label class="toggle-row">
                <span>Compact Mode</span>
                <input type="checkbox" class="toggle-switch" @bind="_compactMode" />
            </label>

            <div class="preview-area">
                <h4>Live Preview</h4>
                <div class="preview-card @_theme.ToLowerInvariant()-theme @(_compactMode ? "compact" : "")"
                     style="font-size: @GetPreviewFontSize()">
                    <div class="preview-header">Dashboard</div>
                    <p class="preview-text">
                        This is how your content will look with the selected appearance settings.
                    </p>
                    <div class="preview-meta">Language: @_language • Font: @_fontSize • @_theme mode</div>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>

            @if (_successMessage is not null)
            {
                <div class="toast success">@_successMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewFontSize() => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private async Task SaveAppearance()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        _successMessage = "Appearance saved!";
        _ = DismissToastAsync();
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

