@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings
@using sv_5abde9ea4cc94681bbd40a33fead36ea.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p class="loading-text">Loading profile…</p>
    }
    else if (_profile is not null)
    {
        <div class="profile-form">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar for @_displayName" />
                </div>
                <span class="avatar-url-label">@_avatarUrl</span>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" @bind="_bio" rows="4"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn btn-secondary" @onclick="DiscardChanges">Discard Changes</button>
            </div>

            @if (_successMessage is not null)
            {
                <div class="toast success">@_successMessage</div>
            }
        </div>
    }
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields(_profile);
        _loading = false;
    }

    private void PopulateFields(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveChanges()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _saving = false;
        _successMessage = "Profile saved successfully!";
        _ = DismissToastAsync();
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }

    private void DiscardChanges()
    {
        if (_profile is not null)
            PopulateFields(_profile);
        _successMessage = null;
    }
}

