+@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings
+@using sv_5abde9ea4cc94681bbd40a33fead36ea.Services
+@inject ISettingsService SettingsService
+
+<div class="settings-section">
+    <h2>Notifications</h2>
+
+    @if (_loading)
+    {
+        <p class="loading-text">Loading notification preferences…</p>
+    }
+    else
+    {
+        <div class="notification-form">
+            <div class="toggle-group">
+                <label class="toggle-row">
+                    <span>Email Notifications</span>
+                    <input type="checkbox" class="toggle-switch" @bind="_emailNotifications" />
+                </label>
+                <label class="toggle-row">
+                    <span>Push Notifications</span>
+                    <input type="checkbox" class="toggle-switch" @bind="_pushNotifications" />
+                </label>
+                <label class="toggle-row">
+                    <span>Weekly Digest</span>
+                    <input type="checkbox" class="toggle-switch" @bind="_weeklyDigest" />
+                </label>
+            </div>
+
+            <div class="channels-section">
+                <h4>Muted Channels</h4>
+                <div class="channel-list">
+                    @foreach (var channel in _channels)
+                    {
+                        <label class="channel-row">
+                            <input type="checkbox"
+                                   checked="@_mutedChannels.Contains(channel)"
+                                   @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
+                            <span>#@channel</span>
+                        </label>
+                    }
+                </div>
+            </div>
+
+            <div class="form-actions">
+                <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
+                    @(_saving ? "Saving…" : "Save Preferences")
+                </button>
+            </div>
+
+            @if (_successMessage is not null)
+            {
+                <div class="toast success">@_successMessage</div>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    private bool _loading = true;
+    private bool _saving;
+    private bool _emailNotifications;
+    private bool _pushNotifications;
+    private bool _weeklyDigest;
+    private List<string> _channels = [];
+    private HashSet<string> _mutedChannels = [];
+    private string? _successMessage;
+
+    protected override async Task OnInitializedAsync()
+    {
+        var prefs = await SettingsService.GetNotificationPrefsAsync();
+        _emailNotifications = prefs.EmailNotifications;
+        _pushNotifications = prefs.PushNotifications;
+        _weeklyDigest = prefs.WeeklyDigest;
+        _channels = prefs.MutedChannels;
+        _mutedChannels = [.. prefs.MutedChannels];
+        _loading = false;
+    }
+
+    private void ToggleChannel(string channel, bool muted)
+    {
+        if (muted)
+            _mutedChannels.Add(channel);
+        else
+            _mutedChannels.Remove(channel);
+    }
+
+    private async Task SavePreferences()
+    {
+        _saving = true;
+        var prefs = new NotificationPrefs(
+            _emailNotifications,
+            _pushNotifications,
+            _weeklyDigest,
+            _mutedChannels.ToList());
+        await SettingsService.SaveNotificationPrefsAsync(prefs);
+        _saving = false;
+        _successMessage = "Preferences saved!";
+        _ = DismissToastAsync();
+    }
+
+    private async Task DismissToastAsync()
+    {
+        await Task.Delay(3000);
+        _successMessage = null;
+        await InvokeAsync(StateHasChanged);
+    }
+}
+

