@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings
@using sv_5abde9ea4cc94681bbd40a33fead36ea.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Security</h2>

    @if (_loading)
    {
        <p class="loading-text">Loading security settings…</p>
    }
    else if (_security is not null)
    {
        <div class="security-form">
            <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

            <div class="tfa-section">
                <div class="toggle-row">
                    <div>
                        <span class="tfa-label">Two-Factor Authentication</span>
                        <span class="tfa-status @(_twoFactorEnabled ? "enabled" : "disabled")">
                            @(_twoFactorEnabled ? "● Enabled" : "○ Disabled")
                        </span>
                    </div>
                    <input type="checkbox" class="toggle-switch" @bind="_twoFactorEnabled" />
                </div>
                @if (_security.LastPasswordChange.HasValue)
                {
                    <p class="last-changed">
                        Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </p>
                }
            </div>

            <ActiveSessionsTable
                Sessions="_security.Sessions"
                CurrentSessionId="sess-1"
                OnRevokeSession="HandleRevokeSession" />
        </div>
    }
</div>

@code {
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _security.TwoFactorEnabled;
        _loading = false;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }
}

