.option-group {
    border: none;
    padding: 0;
    margin: 0 0 1.25rem;
}

.option-group legend {
    font-weight: 600;
    font-size: 0.95rem;
    margin-bottom: 0.5rem;
}

.radio-group {
    display: flex;
    gap: 1.25rem;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.375rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.radio-option input[type="radio"] {
    accent-color: var(--accent-color, #0d6efd);
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 0;
    margin-bottom: 1.25rem;
    border-bottom: 1px solid var(--border-color, #eee);
    font-size: 0.95rem;
}

.toggle-switch {
    width: 2.5rem;
    height: 1.25rem;
    accent-color: var(--accent-color, #0d6efd);
    cursor: pointer;
}

/* Live preview */
.preview-area {
    margin-bottom: 1.5rem;
}

.preview-area h4 {
    margin: 0 0 0.5rem;
    font-size: 1rem;
}

.preview-card {
    border: 1px solid var(--border-color, #dee2e6);
    border-radius: 8px;
    padding: 1.25rem;
    transition: all 0.2s;
}

.preview-card.compact {
    padding: 0.625rem 1rem;
}

.preview-card.light-theme {
    background: #ffffff;
    color: #212529;
}

.preview-card.dark-theme {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-card.system-theme {
    background: #f5f5f5;
    color: #333;
    border-color: #bbb;
}

.preview-header {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.preview-card.compact .preview-header {
    margin-bottom: 0.25rem;
}

.preview-text {
    margin: 0 0 0.5rem;
    line-height: 1.5;
}

.preview-card.compact .preview-text {
    margin-bottom: 0.25rem;
    line-height: 1.3;
}

.preview-meta {
    font-size: 0.75em;
    opacity: 0.65;
}

