arguments.file_text:
@page "/settings"
@namespace sv_5abde9ea4cc94681bbd40a33fead36ea.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="HandleSectionChanged" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";

    private void HandleSectionChanged(string section)
    {
        _activeSection = section;
    }
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    background: var(--page-bg, #fff);
}

.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 720px;
    overflow-y: auto;
}

/* Shared section styles */
::deep .settings-section h2 {
    margin: 0 0 1.5rem;
    font-size: 1.4rem;
    font-weight: 600;
    color: var(--text-primary, #212529);
}

::deep .loading-text {
    color: var(--text-secondary, #6c757d);
    font-style: italic;
}

::deep .form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    margin-bottom: 1rem;
}

::deep .form-group label {
    font-weight: 500;
    font-size: 0.875rem;
    color: var(--text-secondary, #495057);
}

::deep .form-group input[type="text"],
::deep .form-group input[type="email"],
::deep .form-group input[type="password"],
::deep .form-group textarea,
::deep .form-group select {
    padding: 0.5rem 0.75rem;
    border: 1px solid var(--border-color, #ced4da);
    border-radius: 6px;
    font-size: 0.9rem;
    transition: border-color 0.15s;
    background: var(--input-bg, #fff);
    color: var(--text-primary, #212529);
}

::deep .form-group input:focus,
::deep .form-group textarea:focus,
::deep .form-group select:focus {
    outline: none;
    border-color: var(--accent-color, #0d6efd);
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.15);
}

::deep .form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
    margin-bottom: 1rem;
}

::deep .btn {
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background-color 0.15s, opacity 0.15s;
}

::deep .btn:disabled {
    opacity: 0.65;
    cursor: not-allowed;
}

::deep .btn-primary {
    background: var(--accent-color, #0d6efd);
    color: #fff;
}

::deep .btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

::deep .btn-secondary {
    background: var(--secondary-bg, #6c757d);
    color: #fff;
}

::deep .btn-secondary:hover:not(:disabled) {
    background: #5c636a;
}

::deep .btn-danger {
    background: #dc3545;
    color: #fff;
}

::deep .btn-danger:hover:not(:disabled) {
    background: #bb2d3b;
}

::deep .toast {
    margin-top: 0.75rem;
    padding: 0.625rem 1rem;
    border-radius: 6px;
    font-size: 0.875rem;
    font-weight: 500;
    animation: toast-in 0.25s ease-out;
}

::deep .toast.success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

::deep .message {
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    font-size: 0.85rem;
}

::deep .message.error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

::deep .message.success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

@keyframes toast-in {
    from {
        opacity: 0;
        transform: translateY(-8px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

